import "./index.css";
import { Composition } from "remotion";
import { CatSample } from "./CatSample";

export const RemotionRoot: React.FC = () => {
  return (
    <>
      <Composition
        id="CatSample"
        component={CatSample}
        durationInFrames={240}
        fps={30}
        width={1920}
        height={1080}
      />
    </>
  );
};
