import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

const blinkValue = (frame: number, startFrame: number, duration: number) => {
  const progress = (frame - startFrame) / duration;
  if (progress < 0 || progress > 1) {
    return 1;
  }

  return 1 - Math.sin(progress * Math.PI) * 0.96;
};

const Cloud: React.FC<{
  left: number;
  top: number;
  scale: number;
}> = ({ left, top, scale }) => {
  return (
    <div
      style={{
        position: "absolute",
        left,
        top,
        width: 220 * scale,
        height: 90 * scale,
      }}
    >
      <div
        style={{
          position: "absolute",
          left: 0,
          top: 26 * scale,
          width: 170 * scale,
          height: 64 * scale,
          borderRadius: 80,
          backgroundColor: "rgba(255,255,255,0.92)",
        }}
      />
      <div
        style={{
          position: "absolute",
          left: 54 * scale,
          top: 0,
          width: 88 * scale,
          height: 70 * scale,
          borderRadius: 60,
          backgroundColor: "rgba(255,255,255,0.92)",
        }}
      />
      <div
        style={{
          position: "absolute",
          left: 122 * scale,
          top: 14 * scale,
          width: 78 * scale,
          height: 58 * scale,
          borderRadius: 60,
          backgroundColor: "rgba(255,255,255,0.92)",
        }}
      />
    </div>
  );
};

export const CatSample: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const intro = spring({
    fps,
    frame,
    config: {
      damping: 14,
      stiffness: 80,
      mass: 0.8,
    },
  });

  const verticalBounce = Math.sin((frame / fps) * Math.PI * 3) * 10;
  const catY = interpolate(intro, [0, 1], [180, 0]) + verticalBounce;
  const eyeScaleY = [34, 110, 174, 226].reduce((value, start) => {
    return Math.min(value, blinkValue(frame, start, 7));
