    input.type === 'image'
      ? 'Nanobanana image'
      : input.type === 'video'
        ? 'Veo video'
        : 'Hera animation',
    input.type === 'image' ? '#fbcfe8' : input.type === 'video' ? '#bfdbfe' : '#ddd6fe',
