type TopNavigationProps = {
  persistenceStatus: 'local-only' | 'loading' | 'ready' | 'saving' | 'saved' | 'error';
  persistenceError?: string | null;
};

function getStatusLabel(status: TopNavigationProps['persistenceStatus']) {
  if (status === 'local-only') {
    return 'Local only';
  }

  if (status === 'loading') {
    return 'Loading';
  }

  if (status === 'saving') {
    return 'Saving';
  }

  if (status === 'saved') {
    return 'Saved';
  }

  if (status === 'error') {
    return 'Sync error';
  }

  return 'Ready';
}

