            newDestKeys.push(k);
          } else {
            newDestKeys.push(dk);
          }
        }
        setValueByPath(dataRecord, newDestKeys, v);
      }

      for (const k of keysToMove) {
        delete dataRecord[k];
      }
    }
  } else {
    // Navigate to next level
    const dataRecord = data as Record<string, unknown>;
    if (key in dataRecord) {
      _moveValueRecursive(
        dataRecord[key],
        sourceKeys,
        destKeys,
        keyIdx + 1,
        excludeKeys,
      );
    }
  }
