        -20,
      ),
    );

    payload.edges?.push({
      sourceKey: 'research-note',
      targetKey: 'generation-result',
    });
  }

  if (input.audio?.enabled) {
    try {
      const audio = await synthesizeWithGradium({
        text: narrationScript,
        voiceId: input.audio.voiceId,
