export async function generateVideoWithVertex(prompt: string): Promise<VertexVideoOutput> {
  const client = getVertexClient();

  if (!client) {
    throw new Error(
      'Google GenAI is not configured. Set ADC project/location or GOOGLE_API_KEY.',
    );
  }

  const model = process.env.VERTEX_VIDEO_MODEL ?? DEFAULT_VIDEO_MODEL;
  let operation = await client.models.generateVideos({
    model,
    source: {
      prompt,
    },
    config: {
      numberOfVideos: 1,
      durationSeconds: Number(process.env.VERTEX_VIDEO_DURATION_SECONDS ?? 8),
      aspectRatio: process.env.VERTEX_VIDEO_ASPECT_RATIO ?? '16:9',
      resolution: process.env.VERTEX_VIDEO_RESOLUTION ?? '720p',
      generateAudio: false,
      enhancePrompt: true,
    },
  });

  const maxPolls = Number(process.env.VERTEX_VIDEO_MAX_POLLS ?? 18);
  const pollDelayMs = Number(process.env.VERTEX_VIDEO_POLL_DELAY_MS ?? 5000);

  for (let attempt = 0; !operation.done && attempt < maxPolls; attempt += 1) {
    await new Promise((resolve) => setTimeout(resolve, pollDelayMs));
    operation = await client.operations.getVideosOperation({ operation });
  }

  if (!operation.done) {
    throw new Error('Vertex video generation timed out before completion');
  }

  const video = operation.response?.generatedVideos?.[0]?.video;

  if (!video) {
    throw new Error('Vertex video generation did not return a video payload');
  }

  if (video.videoBytes) {
    const mimeType = video.mimeType ?? 'video/mp4';

    return {
      model,
      mimeType,
      dataUrl: `data:${mimeType};base64,${video.videoBytes}`,
    };
  }

  if (video.uri) {
    return {
      model,
      mimeType: video.mimeType,
      uri: video.uri,
    };
  }

  throw new Error('Vertex video generation returned no playable URI or bytes');
}

