export type TavilySearchInput = {
  query: string;
  includeImages?: boolean;
  maxResults?: number;
};

export type TavilyCitation = {
  title: string;
  url: string;
  content: string;
  score?: number;
};

export type TavilySearchOutput = {
  query: string;
  summary: string;
  citations: TavilyCitation[];
  images: string[];
};

type TavilyResponse = {
  query?: string;
  answer?: string;
  images?: string[];
  results?: Array<{
    title?: string;
    url?: string;
    content?: string;
    score?: number;
  }>;
};

const DEFAULT_ENDPOINT = 'https://api.tavily.com/search';

function compactText(value: string, max = 220) {
  const normalized = value.replace(/\s+/g, ' ').trim();
  if (normalized.length <= max) {
    return normalized;
  }

  return `${normalized.slice(0, max - 1)}…`;
}

export async function searchWithTavily(
  input: TavilySearchInput,
): Promise<TavilySearchOutput> {
  const apiKey = process.env.TAVILY_API_KEY;

  if (!apiKey) {
    throw new Error('TAVILY_API_KEY is not set');
  }

  const response = await fetch(process.env.TAVILY_SEARCH_URL ?? DEFAULT_ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    cache: 'no-store',
    body: JSON.stringify({
      api_key: apiKey,
      query: input.query,
      search_depth: 'advanced',
      include_answer: true,
      include_images: Boolean(input.includeImages),
      max_results: input.maxResults ?? 6,
    }),
  });

  if (!response.ok) {
    const details = await response.text();
    throw new Error(`Tavily search failed (${response.status}): ${details}`);
  }

  const payload = (await response.json()) as TavilyResponse;
  const citations = (payload.results ?? [])
    .filter((result) => result.url)
    .map((result) => ({
      title: result.title?.trim() || 'Untitled source',
      url: result.url as string,
      content: compactText(result.content ?? ''),
      score: result.score,
    }));

  const summary = payload.answer?.trim()
    ? payload.answer.trim()
    : citations.length
      ? citations
          .slice(0, 3)
          .map((citation) => citation.content)
          .join(' ')
      : `No Tavily results were returned for "${input.query}".`;

  return {
    query: payload.query?.trim() || input.query,
    summary: compactText(summary, 420),
    citations,
    images: (payload.images ?? []).slice(0, 6),
  };
}

export type GradiumInput = {
  text: string;
  voiceId?: string;
  outputFormat?:
    | 'wav'
    | 'pcm'
    | 'opus'
    | 'ulaw_8000'
    | 'alaw_8000'
    | 'pcm_8000'
    | 'pcm_16000'
    | 'pcm_24000';
};

export type GradiumOutput = {
  mimeType: string;
  dataUrl: string;
  format: string;
};

const DEFAULT_TTS_ENDPOINT = 'https://api.gradium.ai/api/post/speech/tts';

function getMimeTypeFromFormat(format: string) {
  if (format === 'wav') {
    return 'audio/wav';
  }

  if (format === 'opus') {
    return 'audio/ogg';
  }

  if (format === 'ulaw_8000' || format === 'alaw_8000') {
    return 'audio/basic';
  }

  return 'audio/L16';
}

export async function synthesizeWithGradium(
  input: GradiumInput,
): Promise<GradiumOutput> {
  const apiKey = process.env.GRADIUM_API_KEY;

  if (!apiKey) {
    throw new Error('GRADIUM_API_KEY is not set');
  }

  const outputFormat = input.outputFormat ?? 'wav';

  const response = await fetch(process.env.GRADIUM_TTS_URL ?? DEFAULT_TTS_ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
    },
    cache: 'no-store',
    body: JSON.stringify({
      text: input.text,
      voice_id: input.voiceId ?? process.env.GRADIUM_DEFAULT_VOICE_ID ?? 'YTpq7expH9539ERJ',
      output_format: outputFormat,
      only_audio: true,
    }),
  });

  if (!response.ok) {
    const details = await response.text();
    throw new Error(`Gradium TTS failed (${response.status}): ${details}`);
  }

  const bytes = Buffer.from(await response.arrayBuffer());
  const mimeType = getMimeTypeFromFormat(outputFormat);

  return {
    mimeType,
    format: outputFormat,
    dataUrl: `data:${mimeType};base64,${bytes.toString('base64')}`,
  };
}

