        await saveCanvasState(client, { nodes: rawNodes, edges });
        setPersistenceStatus('saved');
        setPersistenceError(null);
      } catch (error) {
        setPersistenceStatus('error');
        setPersistenceError(
          error instanceof Error ? error.message : 'Failed to save canvas',
