      includeResearch: false,
      brandNotes: 'Primary colors #002B5B and #00B7C2. Premium, concise CTA.',
    }),
  });

  if (!response.ok) {
    const details = await response.text();
    throw new Error(`Failed to create job (${response.status}): ${details}`);
  }

  return response.json();
}

