  for (let attempt = 1; attempt <= maxPolls; attempt += 1) {
    const response = await fetch(`${baseUrl}/api/jobs/${jobId}`);

    if (!response.ok) {
      const details = await response.text();
      throw new Error(`Failed to fetch job (${response.status}): ${details}`);
